class FileAccessControl:
    def __init__(self, db: Database, cache_ttl_seconds: float = 0.0, encoding: str = "utf-8"):
        self.db = db
        self.cache = PermissionCache(ttl_seconds=cache_ttl_seconds)
        self.encoding = encoding

    def invalidate_permission(self, user_id: Optional[str] = None, file_id: Optional[str] = None) -> None:
        self.cache.invalidate(user_id=user_id, file_id=file_id)

    def check_permission(self, user_id: str, file_id: str) -> PermissionDecision:
        cached = self.cache.get(user_id, file_id)
        if cached is not None:
            return cached

        file_info = self.db.get_file_info(file_id)
        if file_info is None:
            decision = PermissionDecision(
                allowed=False,
                required_level=10**9,
                user_level=-10**9,
                checked_at_epoch=time.time(),
            )
            self.cache.set(user_id, file_id, decision)
            return decision

        _, required_level = file_info

        user_level = self.db.get_user_level(user_id)
        if user_level is None:
            user_level = -10**9

        acl_level = self.db.get_user_file_acl_level(user_id, file_id)
        effective_level = acl_level if acl_level is not None else user_level

        allowed = effective_level >= required_level
        decision = PermissionDecision(
            allowed=bool(allowed),
            required_level=int(required_level),
            user_level=int(effective_level),
            checked_at_epoch=time.time(),
        )
        self.cache.set(user_id, file_id, decision)
        return decision

    def read_file(self, user_id: str, file_id: str) -> str:
        decision = self.check_permission(user_id, file_id)
        if not decision.allowed:
            raise AccessDeniedError(
                f"User '{user_id}' denied for file '{file_id}' "
                f"(user_level={decision.user_level}, required_level={decision.required_level})"
            )

        file_info = self.db.get_file_info(file_id)
        if file_info is None:
            raise FileNotFoundErrorOnDisk(f"Unknown file_id '{file_id}'")

        path, _ = file_info
        try:
            with open(path, "r", encoding=self.encoding) as f:
                return f.read()
        except FileNotFoundError as e:
            raise FileNotFoundErrorOnDisk(str(e)) from e


